// Pega o corpo da requisição corretamente
const input = $json || {};
const body = input.body || {}; 

// Aceita formatos: { mode:'update', overrides:{...} } ou { origem:'audit-manual', ativos:{...} }
const hasOverrides = body && body.mode === 'update' && body.overrides && Object.keys(body.overrides).length > 0;
const hasAtivos = body && body.ativos && Object.keys(body.ativos).length > 0;

// Validar data_especifica se enviada
if (body.data_especifica && !/^\d{4}-\d{2}-\d{2}$/.test(body.data_especifica)) {
  return [{ json: { status: 'erro', code: 400, msg: 'data_especifica deve estar no formato YYYY-MM-DD' } }];
}

if (!hasOverrides && !hasAtivos) {
  // Se chegamos aqui, é porque ele não achou os dados no lugar certo
  return [{ json: { status: 'erro', code: 400, msg: 'Payload inválido: envie ativos dentro do body' } }];
}

// Retorna apenas o conteúdo do body para os próximos nós
return [{ json: body }];

const body = $json || {};
const ativosManual = body.ativos || {};
const overrides = body.overrides || {};
const dataEspecifica = body.data_especifica; // ← ADICIONAR ESTA LINHA
const map = (v) => (v != null ? { preco: v } : undefined);
const ativos = {
  usd: ativosManual.usd || map(overrides.usd),
  eur: ativosManual.eur || map(overrides.eur),
  milho: ativosManual.milho || map(overrides.milho),
  soja: ativosManual.soja || map(overrides.soja),
  boi: ativosManual.boi || map(overrides.boi),
  madeira: ativosManual.madeira || map(overrides.madeira),
  carbono: ativosManual.carbono || map(overrides.carbono)
};
const result = { origem:'audit-manual', ativos, timestamp: new Date().toISOString() };
if (dataEspecifica) result.data_especifica = dataEspecifica; // ← ADICIONAR SE EXISTIR
return [{ json: result }];

const body = $('🟢 Manual Overrides').first().json || {};
const o = body.ativos || {};
const dataEspecifica = body.data_especifica; // Data enviada pelo painel

const now = new Date();
const iso = now.toISOString();

// Usar data específica se enviada, senão usar atual
const dateId = dataEspecifica || iso.split('T')[0];
const br = dataEspecifica ? 
  new Date(dataEspecifica + 'T00:00:00').toLocaleDateString('pt-BR') : 
  now.toLocaleDateString('pt-BR');

function base(label, val, moeda){ 
  if(!val || val.preco==null) return null; 
  const p = Number(val.preco); 
  return { 
    ativo: label, 
    data: br, 
    ultimo: p, 
    abertura: p, 
    maxima: p, 
    minima: p, 
    volume: null, 
    variacao_pct: null, 
    moeda, 
    fonte: 'Audit-Manual', 
    timestamp: iso, 
    status: 'sucesso', 
    documentId: dateId  // ← USA DATA ESPECÍFICA OU ATUAL
  }; 
}

return [{ json: {
  usd: base('USD/BRL', o.usd, 'BRL'),
  eur: base('EUR/BRL', o.eur, 'BRL'),
  milho: base('Milho Futuros', o.milho, 'BRL'),
  soja: base('Soja Futuros', o.soja, 'USD'),
  boi: base('Boi Gordo', o.boi, 'BRL'),
  madeira: base('Madeira Serrada', o.madeira, 'USD'),
  carbono: base('Carbono', o.carbono, 'EUR')
} }];

const dateId = $('📅 Resolver Data').first().json.dateId;
const mapped = $('🗺️ Mapear Bases').first().json || {};
const sobrescritos = Object.keys(mapped).filter(k => mapped[k]);
return [{ json: {
  status: 'ok',
  modo: 'auditoria-inline',
  documentId: dateId,
  sobrescritos,
  derivados: ['ch2o_agua','custo_agua','pdm','ucs','ucs_ase','vus','carbono_crs','Agua_CRS','vmad','valor_uso_solo'],
  timestamp: new Date().toISOString()
}}];

try {
  const jsonResponse = $input.first().json;
  const originalData = $('⚙️ Processar Dados').first().json;

  if (jsonResponse.status === 'erro') {
    return [{
      json: {
        status: 'erro_json',
        erro: jsonResponse.erro,
        dados_originais: originalData,
        timestamp: new Date().toISOString()
      }
    }];
  }

  return [{
    json: {
      status: 'sucesso',
      mensagem: 'Dados salvos no JSON com sucesso',
      dados_salvos: originalData,
      arquivo: jsonResponse.arquivo,
      timestamp: new Date().toISOString()
    }
  }];

} catch (error) {
  return [{
    json: {
      status: 'erro_final',
      erro: 'Erro na resposta final: ' + error.message,
      timestamp: new Date().toISOString()
    }
  }];
}

try {
  // Coletar apenas os dados do milho
  const milho = $('💾 Salvar no JSON').first()?.json || null;

  // Estruturar JSON final apenas com milho
  const cotacoesConsolidadas = {
    metadata: {
      timestamp: new Date().toISOString(),
      data_coleta: new Date().toLocaleDateString('pt-BR'),
      total_ativos: milho ? 1 : 0,
      fonte: 'Investing.com'
    },
    commodities: {
      agricolas: {
        milho: milho?.dados_formatados?.dados || null
      }
    },
    status: {
      milho: milho?.status || 'erro'
    }
  };

  return [{ json: cotacoesConsolidadas }];

} catch (error) {
  return [{
    json: {
      erro: 'Erro ao consolidar cotações: ' + error.message,
      timestamp: new Date().toISOString(),
      status: 'erro_consolidacao'
    }
  }];
}

// Retornar o JSON consolidado final
const dadosConsolidados = $input.first().json;

return [{
  json: {
    mensagem: 'Cotações consolidadas com sucesso!',
    dados: dadosConsolidados,
    timestamp: new Date().toISOString()
  }
}];

try {
  // Receber dados do salvamento
  const dadosSalvos = $input.first().json;

  return [{
    json: {
      status: 'sistema_completo',
      mensagem: 'Sistema de consolidação executado com sucesso!',
      resultado: dadosSalvos,
      total_cotacoes: 7,
      timestamp_final: new Date().toISOString(),
      resumo: {
        commodities_agricolas: 3,
        commodities_materiais: 2,
        moedas: 2,
        status_geral: dadosSalvos.status
      }
    }
  }];

} catch (error) {
  return [{ json: {
    status: 'erro_sistema',
    erro: 'Erro no sistema final: ' + error.message,
    timestamp: new Date().toISOString()
  } }];
}

